"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[35584],{24106:(e,t,r)=>{r.r(t),r.d(t,{data:()=>o});const o={key:"v-4725fd54",path:"/%E8%BD%AF%E4%BB%B6/Chrome.html",title:"Chrome",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"插件",slug:"插件",children:[{level:3,title:"Github相关",slug:"github相关",children:[]},{level:3,title:"其他",slug:"其他",children:[]}]}],git:{updatedTime:1653622739e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"软件/Chrome.md"}},80926:(e,t,r)=>{r.r(t),r.d(t,{default:()=>i});const o=(0,r(57293).uE)('<h1 id="chrome" tabindex="-1"><a class="header-anchor" href="#chrome" aria-hidden="true">#</a> Chrome</h1><h2 id="插件" tabindex="-1"><a class="header-anchor" href="#插件" aria-hidden="true">#</a> 插件</h2><p>Chorm网上应用店:https://chrome.google.com/webstore/category/extensions</p><h3 id="github相关" tabindex="-1"><a class="header-anchor" href="#github相关" aria-hidden="true">#</a> Github相关</h3><h4 id="isometric-contributions" tabindex="-1"><a class="header-anchor" href="#isometric-contributions" aria-hidden="true">#</a> Isometric Contributions</h4><p><strong>更炫酷的3D立体方式渲染 GitHub 贡献图。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><p><strong>下载方式：Chrome 商店搜索 Isometric Contributions</strong></p><h4 id="git-history-browser-extension" tabindex="-1"><a class="header-anchor" href="#git-history-browser-extension" aria-hidden="true">#</a> Git History Browser Extension</h4><p><strong>当您访问 <code>github、gitlab、bitbucket</code> 中的<code>文件</code>时，会为你的浏览器增加一个 <code>Open in Git History</code> 按钮。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><p><strong>点击按钮跳转到更清晰的 <code>git</code> 历史页面，展示该文件的历史变更情况。相比直接使用 <code>git log</code> ，这种方式更友好。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124264.png" alt="image-20220124093749734"></p><p><strong>下载方式：Chrome 商店搜索 Git History Browser Extension</strong></p><h4 id="octotree" tabindex="-1"><a class="header-anchor" href="#octotree" aria-hidden="true">#</a> Octotree</h4><p>官网:https://www.octotree.io/</p><p><strong>我们经常会在 <code>Github</code> 的代码仓库上临时去查找一些文件，每次打开一层目录都要需要刷新，如果嵌套目录非常深是非常痛苦的，使用 <code>Octotree</code> 可以在 <code>GitHub</code> 左侧显示当前项目的目录结构，能轻松找到代码的位置。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><h5 id="octotree插件功能介绍" tabindex="-1"><a class="header-anchor" href="#octotree插件功能介绍" aria-hidden="true">#</a> Octotree插件功能介绍</h5><p><strong>Octotree的特性：</strong> 1.类似 IDE 的非常方便的代码目录树 2.使用 PJAX 的超快代码浏览（很快！） 3.支持公有库和私有库</p><p><strong>Octotree的缺点:</strong></p><p>1.需要初始化的时间，像nodejs这种稍微大一点的代码库要花大概1分钟多有去爬吧</p><p>2.还是初始化的问题，并没有缓存，我自己做的话应该会有缓存，出错的时候再fix就好～</p><h5 id="octotree插件下载安装" tabindex="-1"><a class="header-anchor" href="#octotree插件下载安装" aria-hidden="true">#</a> Octotree插件下载安装</h5><p>第一步，点击下载链接，进入下载页面，下载CRX格式文件</p><p>第二步，在chrome中新开一个TAB，输入：chrome://extensions/ 回车，打开应用管理器，可以看到之前安装的其他应用，然后把刚才下载的CRX格式文件拖到浏览器中。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124877.png" alt="Octotree插件下载安装"></p><h5 id="octotree插件使用说明" tabindex="-1"><a class="header-anchor" href="#octotree插件使用说明" aria-hidden="true">#</a> Octotree插件使用说明</h5><p>1.在chrome浏览器安装好后，在浏览器的右上方会出现octotree插件的按钮！</p><p>2.当你登录了github之后，找到一个库想看源代码的时候，点击图示的按钮，就可以以树形显示项目结构。 <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124303.png" alt="img"></p><ol start="3"><li>可以点击这里直接跳转啦，不用在莫名其妙的文件夹里面找来找去了！</li></ol><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124275.png" alt="img"></p><h4 id="github加速" tabindex="-1"><a class="header-anchor" href="#github加速" aria-hidden="true">#</a> Github加速</h4><p><strong>下载方式：Chrome 商店搜索 Github加速</strong></p><h4 id="octolinker" tabindex="-1"><a class="header-anchor" href="#octolinker" aria-hidden="true">#</a> OctoLinker</h4><p><strong>让你看代码的时候，可以进行更高效的代码连接跳转。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><p><strong>下载方式：Chrome 商店搜索 OctoLinker</strong></p><h4 id="github-hovercard" tabindex="-1"><a class="header-anchor" href="#github-hovercard" aria-hidden="true">#</a> GitHub Hovercard</h4><p><strong>这款插件可以让你在使用 <code>GitHub</code> 的时，很多地方都能弹出悬浮窗，快速显示大量信息。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><p><strong>下载方式：Chrome 商店搜索 GitHub Hovercard</strong></p><h4 id="sourcegraph" tabindex="-1"><a class="header-anchor" href="#sourcegraph" aria-hidden="true">#</a> Sourcegraph</h4><p><strong>让你能在浏览 <code>GitHub</code> 时也能拥有智能提示、转到定义、查找参考，支持20多种语言和其他流行的代码宿主。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><p><strong>下载方式：Chrome 商店搜索 Sourcegraph</strong></p><h4 id="enhanced" tabindex="-1"><a class="header-anchor" href="#enhanced" aria-hidden="true">#</a> Enhanced</h4><p><strong>这个插件支持在 <code>GitHub</code> 中显示仓库大小、每个文件的大小、显示每个文件的下载链接、直接将文件内容复制到剪贴板、在查看文件内容的同时下载文件。</strong></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124439.png" alt="在这里插入图片描述"></p><p><strong>下载方式：Chrome 商店搜索 Enhanced GitHub</strong></p><h4 id="github-dark-theme" tabindex="-1"><a class="header-anchor" href="#github-dark-theme" aria-hidden="true">#</a> GitHub Dark Theme</h4><p>主题</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205271124048.png" alt="image-20220124094657741"></p><p>下载方式：Chrome 商店搜索 GitHub Dark Theme</p><h3 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h3><h4 id="fehelper-前端助手" tabindex="-1"><a class="header-anchor" href="#fehelper-前端助手" aria-hidden="true">#</a> FeHelper(前端助手)</h4><p><strong>下载方式：Chrome 商店搜索 FeHelper</strong></p>',58),a={},i=(0,r(63243).Z)(a,[["render",function(e,t){return o}]])},63243:(e,t)=>{t.Z=(e,t)=>{const r=e.__vccOpts||e;for(const[e,o]of t)r[e]=o;return r}}}]);